"""
MKT Original Commentary — Hebrews chapters 6–9 (gap-fill pass)
Run: python3 scripts/zc-original-hebrews-6-9-gaps.py

Source data used:
- data/interlinear/hebrews.json
- data/translation/draft/mediating/hebrews.json (MKT text)

Key decisions in this range:
- 6:14 eulogon eulogeso: Hebrew infinitive absolute as LXX idiom for absolute divine certainty
- 7:8 martyroumenos hoti ze: textual silence about Melchizedek death treated as positive testimony
- 7:9 hos epos eipein: author hedges corporate-solidarity argument with classical hedging phrase
- 7:24 aparabaton: NT hapax; permanent/non-transferable; combines permanence + exclusivity
- 8:10-12 Jer 31 internalization: dianoia + kardia = whole inner person; ou me mnescho = deliberate covenant release
- 9:4 tabernacle furniture: theological not merely descriptive; each item points to what new covenant fulfills
- 9:16-17 diatheke as will: Hebrews exploits Greek legal sense of will/testament to explain covenant-death logic
- 9:26 synteleia ton aionon: convergence-point of all ages; athetesis = legal annulment of sin
- 9:27-28 hapax: human hapax (die once) mirrors divine hapax (offered once) — deliberate typological pairing
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = json.loads(r'''
{
  "6": {
    "2": "<p><strong>baptismōn didachēs, epitheseōs te cheirōn, anastaseōs te nekrōn kai kritatos aiōniou</strong> — \"the teaching about baptisms, the laying on of hands, the resurrection of the dead, and eternal judgment\" (<em>baptismōn</em>: the plural is notable — Jewish purification rites used multiple ritual washings, and early Christian instruction had to distinguish Christian baptism from Jewish <em>mikveh</em>, John's baptism, and proselyte baptism): <em>cheirōn epithesis</em> (laying on of hands — a formal gesture of commissioning, blessing, or Spirit-conferral used in both OT and NT); <em>anastaseōs nekrōn</em> and <em>kritatos aiōniou</em> (resurrection of the dead and eternal judgment) are paired eschatological realities — the physical resurrection leads directly to the final assize. The six items form a catechetical curriculum.</p>",
    "3": "<p><strong>kai touto poiēsomen, eanper epitrepē ho theos</strong> — \"and God permitting, we will do so\" (<em>eanper epitrepē ho theos</em>: if indeed God permits — <em>eanper</em>: third-class condition expressing contingency; <em>epitrepē</em>: subjunctive of <em>epitrepō</em>: to allow, to turn over to): the brief aside acknowledges that the theological progress the author proposes is itself subject to divine permission. The conditional is not a theological hedge about the author's willingness but a genuine acknowledgment that advancing toward maturity requires divine enablement — the same God who commands maturity must also grant the capacity to move toward it.</p>",
    "5": "<p><strong>kai kalon geusamenous theou rhēma dynameis te mellontos aiōnos</strong> — \"who have tasted the goodness of the word of God and the powers of the coming age\" (<em>geusamenous</em>: having tasted — aorist participle; <em>geuomai</em> means genuine experiential contact, not mere surface acquaintance; cf. Ps 34:8 \"taste and see that the LORD is good\"): <em>kalon rhēma</em> (the goodness/quality of the word): the adjective <em>kalon</em> here is experiential — the word of God proves itself good to those who engage it. <em>Dynameis mellontos aiōnos</em> (powers of the coming age): the miraculous acts performed in the community are advance installments of the age-to-come's power — already operative before the age itself arrives fully.</p>",
    "6": "<p><strong>kai parapersontas, palin anakainizein eis metanoian, anastaurountas heautois ton huion tou theou kai paradeigmatizontas</strong> — \"and who have then fallen away — to restore them again to repentance, since they are crucifying once more the Son of God to their own harm and holding him up to contempt\" (<em>parapersontas</em>: falling alongside/past — NT hapax from <em>parapipto</em>: to fall away, to slip past; the <em>para</em>-prefix suggests falling beside the path): the reason repentance is impossible is stated in the two participial clauses: <em>anastaurountas</em> (crucifying again — <em>ana</em>-: again, anew) and <em>paradeigmatizontas</em> (publicly exposing to shame — from <em>paradeigma</em>: an example displayed publicly). To pursue \"restoration\" to repentance would be to treat the first repentance as insufficient, implying Christ's sacrifice needs repeating.</p>",
    "7": "<p><strong>gē gar hē piousa ton ep' autēs erchomenon pollakis hueton, kai tiktousa botanēn eutheton ekeinois di' hous kai geōrgeitai, metalambanei eulogias apo tou theou</strong> — \"for land that drinks in the rain often falling on it and that produces a crop useful to those for whom it is farmed receives the blessing of God\" (<em>piousa</em>: having drunk — aorist participle; the land's reception of rain is a completed act leading to production; <em>tiktousa botanēn eutheton</em>: producing fit/useful vegetation — <em>euthetos</em>: suited to purpose, well-fitted): the agricultural metaphor: the same rain (the same word, the same gifts of the Spirit) falls on both land types; the difference is not in the rain but in the land's response. The rain does not discriminate.</p>",
    "8": "<p><strong>ekpherouса de akanthas kai tribolous adokimos kai kataras engys, hēs to telos eis kausin</strong> — \"but land that produces thorns and thistles is worthless and in danger of being cursed. In the end it will be burned\" (<em>adokimos</em>: failing the test, rejected, disqualified — from <em>a</em>-privative + <em>dokimazō</em>: to test and approve): land that fails to produce the expected crop fails the test of its purpose; <em>kataras engys</em> (near a curse — not yet cursed, but on the verge): the \"nearness\" language is merciful — it is not certain doom but an imminent danger. <em>To telos eis kausin</em> (the end toward burning): the burning is the agricultural clearing that allows a new planting cycle — judgment with the possibility of renewal, not just annihilation.</p>",
    "9": "<p><strong>pepeismetha de peri hymōn, agapētoi, ta kreissona kai echomena sōtērias, ei kai houtōs laloumen</strong> — \"even though we speak like this, dear friends, we are convinced of better things in your case — the things that belong to salvation\" (<em>pepeismetha</em>: we are persuaded — perfect passive of <em>peithō</em>: the author stands in a state of settled persuasion about his community; the perfect tense conveys an abiding conviction): <em>agapētoi</em> (beloved — a direct address that shifts the emotional register after the severe warning): the turn signals that the warning is not a verdict but a pastoral alert issued to those the author expects to remain faithful. <em>Echomena sōtērias</em> (holding to/touching salvation — <em>echomai</em>: to cling to, to hold onto): the things that accompany salvation.</p>",
    "10": "<p><strong>ou gar adikos ho theos epilathesthai tou ergou hymōn kai tēs agapēs hēs enedeixasthe eis to onoma autou, diakonēsantes tois hagiois kai diakonountes</strong> — \"for God is not unjust so as to overlook your work and the love that you have shown for his name in serving the saints, as you still do\" (<em>ou gar adikos ho theos</em>: for God is not unjust — the divine justice is invoked as the ground of certainty; the community's persevering service cannot go unrewarded because that would be unjust): <em>epilathesthai</em> (to forget — aorist infinitive of <em>epilanthanomai</em>: the divine forgetting is what is ruled out): <em>diakonēsantes... kai diakonountes</em> (having served... and still serving — the aorist + present combination: past service complete and continuing present service).</p>",
    "11": "<p><strong>epithumomen de hekaston hymōn tēn autēn endeiknysthai spoudēn pros tēn plērophorian tēs elpidos achri telous</strong> — \"we want each of you to show this same diligence to the very end, so as to make your hope sure\" (<em>epithumomen</em>: we desire/long for — not merely \"we want\" as a casual preference but earnest longing [<em>epithumia</em> = passionate desire]): <em>plērophorian tēs elpidos</em> (full assurance of hope — <em>plērophoria</em>: full carrying through, complete persuasion, assurance that fills): hope is not uncertain wishing but confident expectation that must be maintained with the same diligence that produced past service. <em>Achri telous</em> (until the end): the endpoint is eschatological — the goal is not just present faithfulness but sustained faith to the consummation.</p>",
    "12": "<p><strong>hina mē nōthroi genēsthe, mimētai de tōn dia pisteōs kai makrothymias klēronountōn tas epangelias</strong> — \"so that you will not be sluggish, but will imitate those who through faith and patient endurance inherit what has been promised\" (<em>nōthroi</em>: sluggish, dull, slow — the same word used in 5:11 for dullness of hearing; here it describes the spiritual torpor that causes one to stop before the finish line): <em>mimētai</em> (imitators — from <em>mimeomai</em>: to imitate, to model oneself on): <em>dia pisteōs kai makrothymias</em> (through faith and long-suffering patience — <em>makrothymia</em>: long-tempered endurance, the opposite of short-tempered capitulation under pressure): faith and <em>makrothymia</em> are the two instruments by which the promised inheritance is received.</p>",
    "14": "<p><strong>legōn, Ei mēn eulogōn eulogēsō se kai plēthynōn plēthynō se</strong> — \"saying: I will surely bless you and give you many descendants\" (Gen 22:17 LXX): <em>eulogōn eulogēsō</em> and <em>plēthynōn plēthynō</em> — the doubled infinitive-verb construction translates the Hebrew infinitive absolute (<em>bāraḵ ʾăbāreḵeḵā</em>): in the LXX, this idiom intensifies the verb to express absolute certainty and completeness. The translation \"I will surely bless / I will surely multiply\" captures this but flattens the rhetorical force of the reduplication that signals an oath-level commitment.</p>",
    "15": "<p><strong>kai houtōs makrothymēsas epetachen tēs epangelias</strong> — \"and so after waiting patiently, Abraham received what was promised\" (<em>makrothymēsas</em>: having endured patiently — aorist participle of <em>makrothymeō</em>: the same <em>makrothymia</em> root of v12): Abraham exemplifies the faith-and-patience combination the community is called to imitate. <em>Epetachen tēs epangelias</em> (received, attained the promise — <em>epetynchanō</em>: to hit the mark, to obtain, to attain): the verb implies directed movement toward a goal that is successfully reached.</p>",
    "16": "<p><strong>anthrōpoi gar kata tou meizonos omnuousin, kai pasēs autois antilogias peras eis bebaiosin ho horkos</strong> — \"for people swear by someone greater than themselves, and the oath ends all dispute by confirming what is said\" (<em>kata tou meizonos omnuousin</em>: they swear by the greater — the invocation of a superior authority [God, or the emperor, or the gods] to back the claim): <em>antilogias peras</em> (end of contradiction/dispute — <em>antilogia</em>: counter-speaking, contradiction): the oath's social function is to terminate debate by placing a claim under divine sanction. <em>Eis bebaiosin</em> (for confirmation — <em>bebaios</em>: legally reliable, secure): the oath makes the statement legally secure.</p>",
    "18": "<p><strong>hina dia duo pragma ametatheton, en hois adynaton pseudesthai theon, ischyran paraklēsin echōmen hoi kataphygontes kratēsai tēs prokeimenēs elpidos</strong> — \"so that by two unchangeable things, in which it is impossible for God to lie, we who have fled for refuge might have strong encouragement to hold fast to the hope set before us\" (<em>adynaton pseudesthai theon</em>: it is impossible for God to lie — the same <em>adynaton</em> of 6:4; what is impossible for apostates to recover is paralleled by what is impossible for God to do, anchoring the impossibility on God's character): <em>kataphygontes</em> (having fled to refuge — the image of the one seeking sanctuary, the city of refuge): the community has already fled to God's promise; they need encouragement to remain, not to flee again.</p>",
    "20": "<p><strong>hopou prodromos hyper hēmōn eisēlthen Iēsous, kata tēn taxin Melchisedek archiereus genomenos eis ton aiōna</strong> — \"where our forerunner, Jesus, has entered on our behalf. He has become a high priest forever, in the order of Melchizedek\" (<em>prodromos</em>: forerunner, one who runs ahead to prepare the way — a NT hapax; the term was used for advance scouting parties and for the first fruits of the harvest): Jesus is not merely the door to the sanctuary but the first to enter it, paving the way for others to follow the same path. <em>Eis ton aiōna</em> (forever) — the permanence of the Melchizedekian priesthood is the guarantee that the anchor holds permanently.</p>"
  },
  "7": {
    "1": "<p><strong>houtos gar ho Melchisedek, basileus Salēm, hiereus tou theou tou hypsistou, ho synantēsas Abraam hypostrephonti apo tēs kopēs tōn basileōn kai eulogēsas auton</strong> — \"this Melchizedek was king of Salem and priest of God Most High. He met Abraham returning from the defeat of the kings and blessed him\" (Gen 14:17-20 summarized): <em>basileus Salēm, hiereus tou theou tou hypsistou</em> — the dual title (king + priest) is the essential characteristic that makes Melchizedek typologically significant; no Levitical priest held both offices. <em>Tou theou tou hypsistou</em> (of God Most High — <em>El Elyon</em>): a divine title that transcends ethnic particularism — Abraham recognized the God whom Melchizedek served as the same God he himself worshipped (Gen 14:22).</p>",
    "4": "<p><strong>theōreite de pēlikos houtos, hō kai dekatēn Abraam edōken ek tōn akrothiniōn ho patriarchēs</strong> — \"just think how great he was: the patriarch Abraham gave him a tenth of the plunder\" (<em>theōreite pēlikos houtos</em>: consider how great this one is — <em>pēlikos</em>: how great in magnitude, how impressive; <em>theōreite</em>: present imperative — ongoing contemplation): the argument from Abraham's action: that <em>ho patriarchēs</em> (the patriarch — the founding father of the covenant people) gave a tithe to Melchizedek establishes Melchizedek's superiority over Abraham, and thus over all who descended from Abraham, including the Levitical priests. <em>Akrothiniōn</em> (top of the pile, best of the spoils): the tithe is of the prime portion, not the leftovers.</p>",
    "5": "<p><strong>kai hoi men ek tōn huiōn Leui tēn hierōsynēn lambanontes entolēn echousin apodekatouto ton laon kata ton nomon, tout' estin tous adelphous autōn, kai per exelēlythōtas ek tēs osphyos Abraam</strong> — \"now the law requires the descendants of Levi who become priests to collect a tenth from the people — that is, from their fellow Israelites — even though they also are descended from Abraham\" (<em>kata ton nomon</em>: according to the law — the Levitical tithe is a legal requirement, not a voluntary act of homage): the irony noted: the Levitical priests collect a tithe from their own kinsmen-in-Abraham, yet Melchizedek — outside the Abrahamic line's priestly structure — received a tithe from Abraham himself. The tithe-giver is acknowledged as the lesser party.</p>",
    "6": "<p><strong>ho de mē genealogoumenos ex autōn dedekatōken Abraam, kai ton echonta tas epangelias eulogēken</strong> — \"this man, however, did not trace his descent from Levi, yet he collected a tenth from Abraham and blessed him who had the promises\" (<em>mē genealogoumenos ex autōn</em>: not being traced in genealogy from them — the Levitical legitimacy rests on genealogical belonging; Melchizedek has no such genealogy and yet exercises superior priestly authority): <em>dedekatōken</em> (has tithed — perfect: the tithing stands as a permanent historical fact with ongoing typological force): <em>ton echonta tas epangelias</em> (the one who has the promises — Abraham, the promise-holder): Melchizedek blessed the one who held the covenant promises, establishing his superiority over the promise-holder himself.</p>",
    "7": "<p><strong>chōris de pasēs antilogias to elatton hypo tou kreittonos eulogeitai</strong> — \"and without doubt the lesser is blessed by the greater\" (<em>chōris pasēs antilogias</em>: without any dispute/contradiction — <em>antilogia</em>: counter-word, objection): the logical axiom: the one who blesses stands in a position of superiority over the one blessed. Since Melchizedek blessed Abraham, Melchizedek is by definition the greater of the two. The axiom is presented as universally acknowledged — <em>chōris pasēs antilogias</em> closes off potential objections.</p>",
    "8": "<p><strong>kai hōde men dekatous apothnēskontes anthrōpoi lambanousin, ekei de martyroumenos hoti zē</strong> — \"in the one case, the tenth is collected by people who die; but in the other case, by him who is testified to be living\" (<em>apothnēskontes anthrōpoi</em>: people who die — present participle: dying people collect tithes in the Levitical system; their mortality is an ongoing condition that limits the system's permanence): <em>martyroumenos hoti zē</em> (testified to be living — the passive <em>martyroumenos</em>: Scripture testifies of Melchizedek's living status by recording no death): the silence of the text about Melchizedek's death is treated as a positive testimony to his living — not biographical speculation but typological reading of textual silence.</p>",
    "9": "<p><strong>kai hōs epos eipein, di' Abraam kai Leui ho dekatous lambanōn dedekatōtai</strong> — \"one might even say that Levi, who collects the tenth, paid the tenth through Abraham\" (<em>hōs epos eipein</em>: so to speak, if one may put it this way — a hedging expression used in classical Greek to introduce a bold or paradoxical statement without full assertion): the author acknowledges the argumentative leap with <em>hōs epos eipein</em>. <em>Dedekatōtai</em> (has been tithed — perfect passive): the argument rests on the concept of corporate solidarity — Levi's existence within Abraham's loins makes Levi participant in Abraham's actions. This is a Semitic concept of solidarity that the author applies to the genealogical-typological argument.</p>",
    "10": "<p><strong>eti gar en tē osphyi tou patros ēn, hote synantēsen autō Melchisedek</strong> — \"because when Melchizedek met Abraham, Levi was still in the body of his ancestor\" (<em>en tē osphyi tou patros</em>: in the loins of the father/ancestor — <em>osphys</em>: loin, the reproductive seat in biblical anthropology): the argument assumes a corporate and physical understanding of generational solidarity: Levi was \"present\" in Abraham in the same sense that Isaac and Jacob were latent in Abraham's biological seed. This is the same logic by which Paul argues that all humanity participated in Adam's sin (Rom 5:12). The typological argument does not require the author to commit to Levi's personal awareness but to the representative structure of ancestry.</p>",
    "12": "<p><strong>metatithemenēs gar tēs hierōsynēs ex anankēs kai nomou metathesis ginetai</strong> — \"for when the priesthood is changed, the law must be changed also\" (<em>metatithemenēs</em>: being changed, being transferred — present passive participle of <em>metatithēmi</em>: to transfer, to remove from one place/condition to another; the same root as <em>ametatheton</em> in 6:17-18): the logical connection between priesthood and law: the Mosaic Torah is structurally organized around the Levitical priesthood (sacrificial law, purity law, the entire cultic apparatus). If the priesthood is superseded, the law itself is reorganized — not annulled but reorganized around the new priesthood of the Melchizedekian type.</p>",
    "13": "<p><strong>eph' hon gar legetai tauta phylēs heterias metesche, aph' hēs oudeis proseschēken tō thysiastēriō</strong> — \"he of whom these things are said belonged to a different tribe, and no one from that tribe has ever served at the altar\" (<em>phylēs heterias metesche</em>: he shared in/belonged to a different tribe — <em>heteros</em>: another of a different kind; the tribe of Judah, not Levi): the factual observation that Jesus descended from Judah is the historical grounding for the argument. <em>Tō thysiastēriō</em> (the altar): the Levitical altar-service was tribe-specific — Judah had no standing there. The Son's priesthood must therefore be of a different order.</p>",
    "14": "<p><strong>prodēlon gar hoti ex Iouda anatetalken ho kyrios hēmōn, eis hēn phylēn peri hiereon Mōysēs ouden elalēsen</strong> — \"for it is clear that our Lord descended from Judah, and in regard to that tribe Moses said nothing about priests\" (<em>prodēlon</em>: openly evident, perfectly clear — the descent from Judah is not disputed): <em>anatetalken</em> (has arisen/risen — perfect of <em>anatellō</em>: to rise as the sun rises, to spring up as a plant springs from the earth; the messianic \"branch\" language of Isa 11:1, Jer 23:5, Zech 3:8 uses this root): the perfect tense indicates a permanent risen state. <em>Peri hiereon Mōysēs ouden elalēsen</em> (Moses said nothing about priests in regard to that tribe): the Torah's silence about Judah as a priestly tribe is itself evidence that the Son's priesthood operates outside Mosaic categories.</p>",
    "15": "<p><strong>kai perissoteron eti katadēlon estin, ei kata tēn homoiotēta Melchisedek anistatatai hiereus heteros</strong> — \"and this is even more clear if another priest like Melchizedek arises\" (<em>perissoteron eti katadēlon</em>: more abundantly yet evident — intensive comparison; <em>katadēlon</em>: thoroughly evident, transparent): the double comparison (<em>perissoteron</em> + <em>eti</em>) emphasizes that the Melchizedek argument makes what was already clear even more transparent. <em>Kata tēn homoiotēta Melchisedek</em> (according to the likeness of Melchizedek): the \"likeness\" (<em>homoiotēs</em>) echoes 4:15 — the same word used for Christ's likeness to human beings in testing; here the structural-priestly likeness to Melchizedek.</p>",
    "17": "<p><strong>martyreitai gar hoti Sy hiereus eis ton aiōna kata tēn taxin Melchisedek</strong> — \"for it is declared: You are a priest forever, in the order of Melchizedek\" (Ps 110:4 cited again): <em>martyreitai</em> (it is testified, it is declared — present passive: Scripture continues to testify, present tense): the Psalm testimony is not a past utterance but a continuing divine declaration. The citation anchors the entire priesthood-argument: the \"forever\" (<em>eis ton aiōna</em>) is the explicit scriptural warrant for the indestructible-life priesthood argument of v16.</p>",
    "18": "<p><strong>athetēsis men gar ginetai proagousēs entolēs dia to autēs asthenēs kai anōpheles</strong> — \"for on the one hand there is a setting aside of a former commandment because of its weakness and uselessness\" (<em>athetēsis</em>: setting aside, annulment — from <em>atheteō</em>: to put away as if it did not exist, to declare null; a legal term): the language is precise about what has been set aside: not the entire Mosaic revelation but the specific <em>entolē</em> (commandment, regulation) concerning Levitical-bodily qualification. <em>Asthenēs kai anōpheles</em> (weak and useless): the Levitical system is not wrong or evil — it is <em>asthenēs</em> (weak, incapable of achieving its stated goal of perfection) and <em>anōpheles</em> (not profitable in the ultimate sense).</p>",
    "19": "<p><strong>ouden gar eteleiōsen ho nomos, epeisagōgē de kreittōnos elpidos, di' hēs engizomen tō theō</strong> — \"for the law made nothing perfect, and a better hope is introduced through which we draw near to God\" (<em>ouden eteleiōsen ho nomos</em>: the law brought nothing to its goal — the telos-root: the law could not bring the worshiper to the telos of the relationship it promised): <em>epeisagōgē</em> (bringing in alongside/in addition — the prefix <em>epi</em> + <em>eis</em>: a supplementary introduction): the better hope is introduced not as a rejection of what preceded but as the fulfillment of what the law pointed toward. <em>Engizomen tō theō</em> (we draw near to God): the goal of the entire priestly system — access to God — is now achieved through the better hope.</p>",
    "20": "<p><strong>kai kath' hoson ou chōris horkōmosia, hoi men gar chōris horkōmosias eisin hiereis gegonotes</strong> — \"and it was not without an oath! Others became priests without any oath\" (<em>horkōmosia</em>: oath-taking, the swearing of an oath — a compound noun appearing only in Hebrews in the NT): the contrast is between the Levitical ordination (governed by Torah regulation without a personal divine oath) and the Melchizedekian appointment (grounded in the divine oath of Ps 110:4). The oath is the second element that makes Jesus's priesthood superior: not only is it of a different order and not only is it eternal, but it is divinely oath-secured.</p>",
    "21": "<p><strong>ho de meta horkōmosias dia tou legontos pros auton, Ōmosen Kyrios kai ou metamelēthēsetai, Sy hiereus eis ton aiōna</strong> — \"but he became a priest with an oath through the one who said to him: The Lord has sworn and will not change his mind: You are a priest forever\" (Ps 110:4): <em>ou metamelēthēsetai</em> (will not repent/change his mind — <em>metamelomai</em>: to have an after-care, to regret and reverse; the divine negative: God does not experience post-oath regret): the oath-formula emphasizes both the irrevocability of the appointment (sworn) and the immutability of the commitment (will not change his mind). The juxtaposition with the mortal-priest succession of v23 makes the contrast stark.</p>",
    "23": "<p><strong>kai hoi men pleiones eisin gegonotes hiereis, dia to thanatō kōluesthai paramenein</strong> — \"now there were many of those priests, since death prevented them from continuing in office\" (<em>kōluesthai paramenein</em>: being prevented from continuing — <em>kōlyō</em>: to hinder, to obstruct; <em>paramenō</em>: to remain alongside, to continue in place): the plurality of Levitical priests is not a mark of the system's strength but of its structural limitation — each priest's death necessitated a successor, creating an inherently interrupted ministry. The many-priests problem is the death-problem: mortality prevents the continuity that effective priesthood requires.</p>",
    "24": "<p><strong>ho de dia to menein auton eis ton aiōna aparabaton echei tēn hierōsynēn</strong> — \"but because Jesus lives forever, he has a permanent priesthood\" (<em>aparabaton</em>: not passing to another, permanent, inviolable — a NT hapax; from <em>a</em>-privative + <em>parabainō</em>: to step past/across): <em>aparabatos</em> means the priesthood cannot be crossed over to another, cannot be transgressed or bypassed; it is perpetual and non-transferable. The word combines the senses of permanence (it does not end) and exclusivity (it cannot be handed to another). <em>Dia to menein auton eis ton aiōna</em> (because of his abiding forever): the indestructible life (v16) is the ontological ground of the non-transferable priesthood.</p>",
    "27": "<p><strong>hos ouk echei kath' hēmeran anankēn, hōsper hoi archiereis, proteron hyper tōn idiōn hamartiōn thysias anapherein, epeita tōn tou laou; touto gar epoiēsen ephapax heauton anenengkas</strong> — \"unlike the other high priests, he does not need to offer sacrifices day after day, first for his own sins, and then for the sins of the people. He sacrificed for their sins once for all when he offered himself\" (<em>kath' hēmeran</em>: according to the day, day by day — the dailiness of the Levitical system is its limitation; not even the annual high-priestly atonement suffices for the accumulation): <em>ephapax</em> (once for all) — the single completed offering is the answer to the daily necessity. <em>Heauton anenengkas</em> (having offered himself — reflexive: the high priest and the sacrifice are the same person, a structural impossibility in Levitical law): the self-offering resolves what no animal sacrifice could — the need for a priest without sin to offer a sacrifice sufficient once for all.</p>",
    "28": "<p><strong>ho nomos gar anthrōpous kathistēsin archieras echontas astheneian, ho logos de tēs horkōmosias tēs meta ton nomon huion eis ton aiōna teteleiōmenon</strong> — \"for the law appoints as high priests men in all their weakness; but the oath, which came after the law, appointed the Son, who has been made perfect forever\" (<em>kata ton nomon</em>: according to the law, governed by the law; <em>echontas astheneian</em>: having weakness — the weakness is not moral infirmity alone but the structural weakness of mortality and its consequences): <em>ho logos tēs horkōmosias</em> (the word of the oath-taking) — the Ps 110:4 oracle is a <em>logos</em> (a word with authority) expressed as an <em>horkōmosia</em> (oath). <em>Teteleiōmenon eis ton aiōna</em> (having been made perfect/complete forever — perfect passive participle): the Son's perfection through suffering (2:10, 5:9) is now permanent; the word \"forever\" closes the argument of chapters 5-7.</p>"
  },
  "8": {
    "2": "<p><strong>tōn hagiōn leitourgos kai tēs skēnēs tēs alēthinēs, hēn epēxen ho kyrios, ouk anthrōpos</strong> — \"who serves in the sanctuary, the true tabernacle set up by the Lord, not by a mere human being\" (<em>leitourgos</em>: liturgist, one who performs public religious service — a priestly/cultic technical term; <em>tōn hagiōn leitourgos</em>: liturgist of the holy things/sanctuary): <em>tēs skēnēs tēs alēthinēs</em> (the true tabernacle — <em>alēthinēs</em>: true, genuine, the original of which others are copies): the <em>alēthinos</em>/<em>alēthēs</em> distinction: <em>alēthinos</em> means \"genuine, real, as opposed to copies and shadows\" rather than merely \"truthful.\" The earthly tabernacle is a copy; this one is the original. <em>Hēn epēxen ho kyrios, ouk anthrōpos</em> (which the Lord pitched, not a human being): the divine construction establishes its nature — not constructed within the created order.</p>",
    "3": "<p><strong>pas gar archiereus eis to prospherein dōra te kai thysias kathistatai; hothen anagkaion echein ti kai touton ho prospherē</strong> — \"every high priest is appointed to offer both gifts and sacrifices, and so it was necessary for this one also to have something to offer\" (<em>eis to prospherein</em>: for the purpose of offering — the infinitive of purpose defines the essential function of the high priest): <em>anagkaion</em> (necessary): the logical necessity follows from the universal: since every high priest must offer, and since Christ is a high priest, Christ must also have an offering. The offering cannot be the repeated animal sacrifices of the Levitical system — his offering is identified as his own self (9:14, 26).</p>",
    "4": "<p><strong>ei men oun ēn epi gēs, oud' an ēn hiereus, ontōn tōn kata nomon proscheron ōra ta dōra</strong> — \"if he were on earth, he would not be a priest at all, since there are priests who offer the gifts prescribed by the law\" (<em>ei men oun ēn epi gēs</em>: if indeed he were on earth — second-class conditional, contrary to fact: the present condition is that Christ is NOT on earth): the argument is about jurisdictional categories: the earthly sphere already has its established priestly order. Christ's priesthood operates in the heavenly sphere — not competing with the Levitical system on its own terrain but fulfilling the reality of which the earthly is only the copy.</p>",
    "7": "<p><strong>ei gar hē prōtē ekeinē ēn amemptos, ouk an deuteras ezēteito topos</strong> — \"for if there had been nothing wrong with that first covenant, no place would have been sought for another\" (<em>ei... ēn amemptos</em>: if it had been blameless — second-class conditional, contrary to fact; <em>amemptos</em>: blameless, without fault): the argument from the existence of Jer 31's new covenant promise: God would not promise what was already provided. The existence of the promise is itself evidence of the first covenant's inadequacy. <em>Amemptos</em> does not imply the first covenant was wrong or evil — but that it was incomplete and incapable of achieving the final goal.</p>",
    "10": "<p><strong>hoti autē hē diathēkē hēn diathēsomai tō oikō Israēl meta tas hēmeras ekeinasmeta tas hēmeras ekeinasdidonai nomous mou eis tēn dianoian autōn, kai epi kardias autōn epigrapsō autous, kai esomai autois eis theon kai autoi esontai moi eis laon</strong> — \"I will put my laws in their minds and write them on their hearts. I will be their God, and they will be my people\" (Jer 31:33 LXX): <em>didonai nomous eis tēn dianoian</em> (giving laws into the mind — <em>dianoia</em>: the faculty of thinking, the mind as the organ of understanding): and <em>epi kardias epigrapsō</em> (I will write upon their hearts — <em>epigrapsō</em>: to write upon, to engrave on): the new covenant's law is internalized — not external tablets but internal inscription. <em>Dianoia</em> (mind/understanding) and <em>kardia</em> (heart) together cover the whole inner person. The covenant formula <em>esomai autois eis theon... autoi... eis laon</em> (I will be to them as God, they will be to me as a people) is the bedrock covenantal language from the Sinai tradition — the new covenant fulfills the same relational goal.</p>",
    "11": "<p><strong>kai ou mē didaxōsin hekastos ton politen autou kai hekastos ton adelphon autou legōn, Gnōthi ton Kyrion, hoti pantes eidēsousin me apo mikrou heōs megalou autōn</strong> — \"no longer will they teach their neighbor, or say to one another, Know the Lord, because they will all know me, from the least of them to the greatest\" (<em>ou mē... didaxōsin</em>: they shall by no means teach — the double negative <em>ou mē</em> + aorist subjunctive is the strongest Greek negation): <em>Gnōthi ton Kyrion</em> (Know the Lord): in the first covenant, external instruction mediated the knowledge of God through priests and prophets; in the new covenant, the knowledge is direct and universal. <em>Pantes eidēsousin me</em> (all shall know me — <em>oida</em>: the perfect-present knowledge that is settled and complete): from the smallest to the greatest — the knowledge transcends social and educational stratification.</p>",
    "12": "<p><strong>hoti hileōs esomai tais adikiais autōn kai tōn hamartiōn autōn ou mē mnēsthō eti</strong> — \"for I will forgive their wickedness and will remember their sins no more\" (Jer 31:34 LXX): <em>hileōs esomai</em> (I will be merciful/gracious — <em>hileōs</em>: propitious, gracious, disposed to forgive; the word used for the Day of Atonement mercy): <em>ou mē mnēsthō eti</em> (I will by no means remember any longer — double negative <em>ou mē</em> + aorist subjunctive + <em>eti</em>: the most emphatic possible negation): the divine \"forgetting\" is not cognitive failure but an act of deliberate covenant release — God will not bring up the forgiven sins as legal evidence. This is the culminating promise of the new covenant: the basis of everything that precedes it in the Jeremiah citation is this final act of complete forgiveness.</p>"
  },
  "9": {
    "1": "<p><strong>eiche men oun hē prōtē dikaiōmata latreias to te hagion kosmikon</strong> — \"now the first covenant had regulations for worship and also an earthly sanctuary\" (<em>dikaiōmata latreias</em>: regulations/ordinances of worship — <em>dikaiōmata</em>: righteous requirements, legally binding ordinances; the word used in Rom 8:4 for what the Spirit fulfills): <em>to hagion kosmikon</em> (the earthly/worldly sanctuary — <em>kosmikon</em>: belonging to the <em>kosmos</em>, the material world-order): the modifier <em>kosmikon</em> immediately flags the earthly sanctuary as belonging to the temporal, material sphere — as opposed to the heavenly sanctuary of ch8. The contrast is built into the description from the first word.</p>",
    "2": "<p><strong>skēnē gar kateskeuasthē hē prōtē en hē hē te lychnia kai hē trapeza kai hē prothesis tōn artōn, hētis legetai Hagia</strong> — \"a tabernacle was set up. In its first room were the lampstand and the table with the consecrated bread; this was called the Holy Place\" (<em>lychnia</em>: the lampstand — the golden menorah of Exod 25:31-40; <em>trapeza kai hē prothesis tōn artōn</em>: the table and the setting-out of the loaves — the table of showbread, Exod 25:23-30, <em>prothesis</em>: the setting-forward, the presentation, the public display): <em>Hagia</em> (Holy Place — the first room, accessible to all priests): the inventory is not merely descriptive but sets up the contrast with what is beyond the second curtain. Each piece of furniture pointed beyond itself to the divine presence.</p>",
    "3": "<p><strong>meta de to deuteron katapetasma skēnē hē legomenē Hagia Hagiōn</strong> — \"behind the second curtain was a room called the Most Holy Place\" (<em>meta to deuteron katapetasma</em>: after/behind the second curtain — <em>katapetasma</em>: the hanging veil/curtain; the same word used for the temple veil torn at the crucifixion in the Synoptics): <em>Hagia Hagiōn</em> (Most Holy Place — superlative construct, lit. Holy of Holies; the Hebrew <em>qodesh qodashim</em>): the spatial structure of the tabernacle embodies a theology of graduated holiness — the outer court, the Holy Place, the Most Holy Place — with increasingly restricted access that Hebrews reads as a pointer to the restricted access of the old covenant.</p>",
    "4": "<p><strong>chrysoun echousa thymiasētrion kai tēn kibōton tēs diathēkēs periekekkalymmēnēn pantothen chrysiō, en hē stamnos chrysē echousa to manna kai hē rhabdos Aarōn hē blastēsasa kai ai plakes tēs diathēkēs</strong> — \"this room had the golden altar of incense and the gold-covered ark of the covenant. Inside the ark were the golden jar of manna, Aaron's staff that had budded, and the stone tablets of the covenant\" (<em>thymiasētrion</em>: the incense altar or incense-vessel — there is scholarly discussion on whether this refers to the altar of incense or the censer; Hebrews may be associating the incense-altar with the Most Holy Place for theological purposes since the incense was burned in connection with the high priest's entry): <em>rhabdos Aarōn hē blastēsasa</em> (the staff of Aaron that budded — Num 17): the three contents of the ark (manna, Aaron's staff, the covenant tablets) are theologically significant — providential sustenance, divine vindication of priesthood, and the covenant law. Each points to what the new covenant fulfills.</p>",
    "6": "<p><strong>toutōn de houtōs kateskeuasmenōn, eis men tēn prōtēn skēnēn dia pantos eisiasin hoi hiereis tas latreias epitelountes</strong> — \"when everything had been arranged like this, the priests entered regularly into the outer room to carry on their ministry\" (<em>dia pantos</em>: continually, at all times — the constant repetition of priestly ministry in the outer room): <em>tas latreias epitelountes</em> (accomplishing/performing the priestly services — <em>epitelountes</em>: present participle, ongoing completion): the daily priestly ministry in the outer room (lampstand tending, incense, showbread) was regular and repeated. The contrast with the inner room (once per year) structures the argument about access and proximity to the divine presence.</p>",
    "8": "<p><strong>touto dēlountos tou pneumatos tou hagiou, mēpō pephanerōsthai tēn tōn hagiōn hodon, eti tēs prōtēs skēnēs echousēs stasin</strong> — \"the Holy Spirit was showing by this that the way into the Most Holy Place had not yet been disclosed as long as the first tabernacle was still standing\" (<em>touto dēlountos tou pneumatos tou hagiou</em>: the Holy Spirit making this clear — <em>dēloō</em>: to make manifest, to reveal; the Spirit is the author of the tabernacle's theological meaning): <em>mēpō pephanerōsthai</em> (not yet to have been made manifest — perfect passive infinitive: the perfect indicates the sustained non-disclosure): the Spirit intentionally encoded the limitation of access into the tabernacle's structure as a theological statement: the way into God's presence was blocked, not because the first tabernacle was temporary but because the sacrifice that opens the way had not yet been made.</p>",
    "9": "<p><strong>hētis parabolē eis ton kairon ton enestēkota</strong> — \"this is an illustration for the present time\" (<em>parabolē</em>: parable, type, illustration — from <em>para</em> + <em>ballō</em>: to throw alongside; a placing-beside-for-comparison): the tabernacle is explicitly called a <em>parabolē</em>, and the \"present time\" (<em>kairon ton enestēkota</em>) is the time of the new covenant's inauguration. The tabernacle's function as parable/type was always its primary theological function. <em>Kata syneidēsin</em> (in relation to conscience — <em>syneidēsis</em>: the shared-knowledge/conscience, the inner moral awareness): the Levitical gifts and sacrifices could not achieve the cleansing that matters — the inner moral-spiritual conscience — only external ceremonial status.</p>",
    "10": "<p><strong>monon epi brōmasin kai posasin kai diaphorois baptismois, dikaiōmata sarkos mechri kairou diorthōseōs epikeimenoi</strong> — \"they are only a matter of food and drink and various ceremonial washings — external regulations applying until the time of the new order\" (<em>dikaiōmata sarkos</em>: ordinances/regulations of flesh — <em>sarx</em> here = the bodily/material dimension; fleshly ordinances as opposed to the spiritual transformation that conscience requires): <em>mechri kairou diorthōseōs</em> (until the time of the setting-right/correction — <em>diorthōsis</em>: a setting-upright, a reformation, a restoration to the correct condition; only here in the NT): the Levitical system was designed with a temporal limit — <em>mechri</em> (until): its validity was always provisional, awaiting the <em>kairos</em> (the appointed time) of the new order.</p>",
    "13": "<p><strong>ei gar to haima tragōn kai taurōn kai spodos damaleos rhantizouśa tous kekoinōmenous hagiaizei pros tēn tēs sarkos katharotēta</strong> — \"if the blood of goats and bulls and the ashes of a heifer sprinkled on those who are ceremonially unclean sanctify them for the purification of the flesh\" (<em>spodos damaleos</em>: ashes of a heifer — the red heifer ritual of Num 19; the ashes mixed with water were sprinkled on those defiled by corpse-contact): <em>kekoinōmenous</em> (those having been defiled — perfect passive: their defilement is an established condition; <em>koinoō</em>: to make common, to defile by contamination): <em>pros tēn tēs sarkos katharotēta</em> (for the cleanness of the flesh): the Levitical purification achieves external, ritual cleanliness — the body is made ceremonially fit for worship — but does not address the moral-spiritual interior.</p>",
    "14": "<p><strong>posō mallon to haima tou Christou, hos dia pneumatos aiōniou heauton prosēnegken amōmon tō theō, katharizei tēn syneidēsin hymōn apo nekrōn ergōn eis to latreuein theō zōnti</strong> — \"how much more, then, will the blood of Christ, who through the eternal Spirit offered himself unblemished to God, cleanse our consciences from acts that lead to death, so that we may serve the living God\" (<em>posō mallon</em>: how much more — the <em>a minori ad maius</em> argument [if the lesser, how much more the greater]): <em>dia pneumatos aiōniou</em> (through the eternal Spirit — <em>aiōniou</em>: belonging to the coming age, eternal): the Spirit's involvement in the self-offering is not merely instrumental but constitutive of its quality — the sacrifice transcends the temporal order by virtue of the Spirit's eternal character. <em>Heauton prosēnegken amōmon</em> (he offered himself unblemished — the reflexive: the priest and the offering are one; <em>amōmos</em>: without spot or blemish, the sacrificial requirement): <em>katharizei tēn syneidēsin</em> (cleanses the conscience — <em>syneidēsin</em>): where the Levitical blood achieved external cleansing, Christ's blood reaches the <em>syneidēsis</em> — the inner moral awareness.</p>",
    "16": "<p><strong>hopou gar diathēkē, thanaton anankē pheresthai tou diathemenou</strong> — \"for where there is a will/covenant, the death of the one who made it must be established\" (<em>diathēkē</em>: will/testament; also covenant — the Greek word covers both): here Hebrews exploits the Greek legal sense of <em>diathēkē</em> as a last will and testament, which only takes effect at death. <em>Thanaton anankē pheresthai</em> (it is necessary for a death to be brought forward/established — <em>pheresthai</em>: to be borne, produced as evidence; the passive suggests a legal presentation of proof): the death of the testator is the condition for the will's validity. This legal logic is applied to the covenant: the new covenant's benefits require the death of the covenant-maker.</p>",
    "17": "<p><strong>diathēkē gar epi nekrois bebaia, epei mēpote ischyei hote zē ho diathemenos</strong> — \"because a will is in force only when somebody has died; it never takes effect while the one who made it is living\" (<em>epi nekrois bebaia</em>: confirmed/secure over/upon the dead — <em>bebaia</em>: legally firm, secure; same <em>bebaios</em> root used throughout for reliability): the legal observation is the argumentative bridge: the old covenant was dedicated with blood at Sinai (v18-20), and the new covenant is inaugurated through the death of its mediator. Both covenants require death for their validity.</p>",
    "18": "<p><strong>hothen oude hē prōtē chōris haimatos enkekainistai</strong> — \"this is why even the first covenant was not put into effect without blood\" (<em>enkekainistai</em>: has been inaugurated, dedicated — perfect passive of <em>enkainizō</em>: to inaugurate, to make new, to consecrate by a fresh act; the <em>kaino</em>-root: the same word group as <em>kainē diathēkē</em> [new covenant]): the irony is noted: the first covenant was <em>enkainizō</em>-d (inaugurated/made new) with blood, and the new covenant is likewise inaugurated with the blood of its mediator. The blood-inauguration pattern is continuous across both covenants.</p>",
    "19": "<p><strong>lalētheisēs gar pasēs entolēs kata ton nomon hypo Mōyseōs panti tō laō, labōn to haima tōn moschōn kai tōn tragōn meta hydatos kai eriou kokkinou kai hyssōpou auto te to biblion kai panta ton laon errantisen</strong> — \"when Moses had proclaimed every commandment of the law to all the people, he took the blood of calves, together with water, scarlet wool and branches of hyssop, and sprinkled both the scroll and all the people\" (Exod 24:6-8 with some elaboration): Hebrews includes details not in the Exodus narrative (calves and goats, water, scarlet wool, hyssop) — possibly drawing on Num 19 or later Jewish tradition. <em>Auto te to biblion</em> (both the scroll itself): the sprinkling of the scroll is not in Exod 24 — Hebrews may be indicating that the written law itself was consecrated with blood, showing the intimate connection between covenant-document and covenant-blood.</p>",
    "20": "<p><strong>legōn, Touto to haima tēs diathēkēs hēs eneteilato pros hymas ho theos</strong> — \"saying: This is the blood of the covenant, which God has commanded you to keep\" (Exod 24:8 LXX): <em>Touto to haima tēs diathēkēs</em> (This is the blood of the covenant): the formula that Jesus reuses at the Last Supper (Matt 26:28; Mark 14:24; Luke 22:20; 1 Cor 11:25) — the verbal link is deliberate and Hebrews' readers would recognize it. The Sinai blood-of-the-covenant becomes the interpretive lens for the crucifixion event; the new covenant's blood-dedication recapitulates and surpasses the Sinai pattern.</p>",
    "21": "<p><strong>kai tēn skēnēn de kai panta ta skeuē tēs leitourgias tō haimati homoiōs errantisen</strong> — \"in the same way, he sprinkled with the blood both the tabernacle and everything used in its ceremonies\" (<em>homoiōs</em>: in the same way, likewise): the tabernacle's blood-dedication extended to all its vessels and furnishings. Hebrews' summary of Levitical inauguration practice goes beyond Exod 24 — the Mosaic consecration of the tabernacle (Exod 40) and its furnishings apparently involved blood in tradition, though the Exodus narrative focuses on anointing oil. The pattern is: everything in the old covenant system had its existence mediated through blood.</p>",
    "23": "<p><strong>anankē oun ta men hypodeigmata tōn en tois ouranois toutois katharizesthai, auta de ta epourania kreittosi thysiais para tautas</strong> — \"it was necessary, then, for the copies of the heavenly things to be purified with these sacrifices, but the heavenly things themselves with better sacrifices than these\" (<em>kreittosi thysiais</em>: better sacrifices — plural): the plural is unexpected since Christ offered one sacrifice. Hebrews uses the plural rhetorically to match the comparison: since the earthly needed purification with multiple sacrifices, the heavenly required \"better\" (single but superior) ones. Alternatively, the plural may encompass all aspects of Christ's sacrificial work. <em>Anankē</em> (necessity): the purification of the heavenly things is necessary because the heavenly sanctuary is the one where Christ presents his self-offering — it must be purified to function as the ultimate Holy of Holies.</p>",
    "25": "<p><strong>oud' hina pollakis prospherē heauton, hōsper ho archiereus eiserchetai eis ta hagia kat' eniauton en haimati allotriō</strong> — \"nor did he enter heaven to offer himself again and again, the way the high priest enters the Most Holy Place every year with blood that is not his own\" (<em>kat' eniauton</em>: year by year, annually — the annual cycle of Day of Atonement entry): <em>en haimati allotriō</em> (with blood belonging to another — <em>allotrios</em>: belonging to another person, foreign, not one's own): the contrast is precise: the Levitical high priest must bring someone else's blood because his own would be unfit; Christ enters with his own blood because he is both priest and sacrifice. The repetition of entry reveals the incompleteness; the once-for-all entry declares the completion.</p>",
    "26": "<p><strong>epei edei auton pollakis pathein apo katabolēs kosmou; nyn de hapax epi synteleia tōn aiōnōn eis athetēsin tēs hamartias dia tēs thysias autou pephanerōtai</strong> — \"otherwise Christ would have had to suffer many times since the creation of the world. But he has appeared once for all at the culmination of the ages to do away with sin by the sacrifice of himself\" (<em>epi synteleia tōn aiōnōn</em>: at the completion/end of the ages — <em>synteleia</em>: joint-completion, the convergence of all the ages at their end-point): the incarnation and sacrifice are placed at the hinge-point of history — the ages converge on this event. <em>Eis athetēsin tēs hamartias</em> (for the setting-aside of sin — <em>athetēsis</em>: the same legal annulment term used in 7:18 for the setting-aside of the former commandment): sin is legally annulled, not merely covered over.</p>",
    "27": "<p><strong>kai kath' hoson apokeitai tois anthrōpois hapax apothansein, meta de touto krisis</strong> — \"just as people are destined to die once, and after that to face judgment\" (<em>apokeitai</em>: it is laid away/stored up/appointed — from <em>apokeimai</em>: what is reserved and waiting; death is humanity's standing appointment): <em>hapax apothansein</em> (to die once): the human \"once\" of death mirrors the divine \"once\" of Christ's sacrifice in v28 — the typological pairing is the rhetorical point: just as humanity dies once and faces judgment once, so Christ was offered once and will appear once for salvation. The universal human pattern (one death, one judgment) is the frame for the particular divine act (one sacrifice, one appearing).</p>"
  }
}
''')

def main():
    existing = load_comm('mkt-original', 'hebrews')
    merge_comm(existing, HEBREWS)
    save_comm('mkt-original', 'hebrews', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Hebrews 6-9 mkt-original gaps filled: {len(existing)} chapters, {total} verses written.')

if __name__ == '__main__':
    main()
